import React from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { 
  LogOut, 
  Cpu, 
  LayoutDashboard, 
  Zap, 
  User, 
  ChevronRight 
} from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  // Helper to check active route for emerald highlighting
  const isActive = (path) => location.pathname === path;

  return (
    <nav className="sticky top-0 z-[100] w-full border-b border-white/5 bg-[#0a0a0a]/80 backdrop-blur-xl">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex h-20 items-center justify-between">
          
          {/* 🧩 Branding: Finify AI Node */}
          <Link to="/" className="flex items-center gap-3 group">
            <div className="p-2 bg-emerald-500/10 rounded-lg border border-emerald-500/20 group-hover:border-emerald-500/50 transition-all">
              <Cpu className="text-emerald-500 group-hover:rotate-90 transition-transform duration-500" size={20} />
            </div>
            <div className="flex flex-col">
              <span className="font-bold tracking-[0.3em] text-white uppercase text-sm">Finify_AI</span>
              <span className="text-[8px] text-emerald-500/50 font-mono tracking-widest uppercase">System_V3.0_Stable</span>
            </div>
          </Link>

          {/* 🛰️ Navigation Matrix */}
          {user ? (
            <div className="flex items-center gap-2 md:gap-8">
              <div className="hidden md:flex items-center gap-6">
                <Link 
                  to="/dashboard" 
                  className={`flex items-center gap-2 text-[10px] uppercase tracking-widest transition-all ${
                    isActive('/dashboard') ? 'text-emerald-500' : 'text-white/40 hover:text-white'
                  }`}
                >
                  <LayoutDashboard size={14} /> Dashboard
                </Link>
                <Link 
                  to="/generate" 
                  className={`flex items-center gap-2 text-[10px] uppercase tracking-widest transition-all ${
                    isActive('/generate') ? 'text-emerald-500' : 'text-white/40 hover:text-white'
                  }`}
                >
                  <Zap size={14} /> Strategy_Engine
                </Link>
              </div>

              {/* Divider */}
              <div className="hidden md:block h-6 w-[1px] bg-white/10" />

              {/* Operator Status & Logout */}
              <div className="flex items-center gap-4">
                <div className="hidden sm:flex flex-col items-end">
                  <div className="flex items-center gap-2 text-[9px] text-emerald-500/80 font-mono">
                    <span className="h-1.5 w-1.5 rounded-full bg-emerald-500 animate-pulse" />
                    NODE_ACTIVE
                  </div>
                  <span className="text-[10px] text-white/20 font-mono truncate max-w-[120px]">
                    {user.email}
                  </span>
                </div>
                
                <button 
                  onClick={handleLogout}
                  className="group flex items-center gap-2 bg-white/5 hover:bg-red-500/10 border border-white/5 hover:border-red-500/30 px-4 py-2 rounded-lg transition-all"
                >
                  <LogOut size={14} className="text-white/40 group-hover:text-red-500 transition-colors" />
                  <span className="text-[10px] font-bold text-white/40 group-hover:text-red-500 uppercase tracking-widest hidden lg:block">
                    Exit_Terminal
                  </span>
                </button>
              </div>
            </div>
          ) : (
            /* Public Actions */
            <div className="flex items-center gap-4">
              <Link to="/login" className="text-[10px] font-bold text-white/40 hover:text-white uppercase tracking-widest transition-colors">
                Login
              </Link>
              <Link to="/register" className="emerald-btn py-2 px-5 text-[10px]">
                Initialize_Node <ChevronRight size={14} />
              </Link>
            </div>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
